import{f as i,D as h,o as e,c,a2 as r,b as o,w as a,a as s,G as l,a5 as d}from"./chunks/framework.Ccw_j35p.js";const q=JSON.parse('{"title":"TCP 拥塞控制","description":"","frontmatter":{},"headers":[],"relativePath":"computer-network/fundamentals/tcp-congestion.md","filePath":"computer-network/fundamentals/tcp-congestion.md","lastUpdated":1780924599000}'),p={name:"computer-network/fundamentals/tcp-congestion.md"};function u(b,t,B,A,g,E){const n=h("Mermaid");return e(),c("div",null,[t[2]||(t[2]=r('<h1 id="tcp-拥塞控制" tabindex="-1">TCP 拥塞控制 <a class="header-anchor" href="#tcp-拥塞控制" aria-label="Permalink to &quot;TCP 拥塞控制&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>考察点</th><th>重要程度</th><th>面试频率</th><th>掌握目标</th></tr></thead><tbody><tr><td>慢启动 vs 拥塞避免</td><td>⭐⭐⭐</td><td>极高</td><td>理解原理、拥塞窗口变化规律</td></tr><tr><td>快重传 vs 快恢复</td><td>⭐⭐⭐</td><td>极高</td><td>触发条件、改进点</td></tr><tr><td>拥塞发生的判断</td><td>⭐⭐⭐</td><td>高</td><td>知道超时和重复确认两种触发方式</td></tr><tr><td>BBR 核心思想</td><td>⭐⭐</td><td>高</td><td>理解带宽时延积、模型与传统的区别</td></tr></tbody></table><hr><h2 id="一、为什么需要拥塞控制" tabindex="-1">一、为什么需要拥塞控制 <a class="header-anchor" href="#一、为什么需要拥塞控制" aria-label="Permalink to &quot;一、为什么需要拥塞控制&quot;">​</a></h2><p>TCP 要保证可靠传输，但如果发送方一味按照接收方通告的窗口全速发送，很可能导致网络中间的路由器和链路不堪重负，造成严重丢包。</p><p><strong>拥塞控制</strong>和<strong>流量控制</strong>是不同的概念：</p><table tabindex="0"><thead><tr><th>对比</th><th>拥塞控制</th><th>流量控制</th></tr></thead><tbody><tr><td>解决问题</td><td>网络负载过载导致的拥塞丢包</td><td>发送方太快淹没接收方</td></tr><tr><td>控制对象</td><td>发送速率受网络状况限制</td><td>发送速率接收方处理能力限制</td></tr><tr><td>控制参数</td><td>拥塞窗口 cwnd</td><td>接收窗口 rwnd</td></tr></tbody></table><p>发送方实际窗口大小：<code>W = min(cwnd, rwnd)</code></p><div class="tip custom-block"><p class="custom-block-title">理解区别</p><p>流量控制是端到端的，只看你接收方能不能处理得了；拥塞控制是全局的，要看整个网络能不能扛得住。就算接收窗口很大，网络已经堵死了，发送方也必须减速。</p></div><hr><h2 id="二、拥塞控制四大核心算法" tabindex="-1">二、拥塞控制四大核心算法 <a class="header-anchor" href="#二、拥塞控制四大核心算法" aria-label="Permalink to &quot;二、拥塞控制四大核心算法&quot;">​</a></h2><p>TCP 拥塞控制发展到现在，主流是四个阶段：<strong>慢启动 → 拥塞避免 → 快重传 → 快恢复</strong>。</p><h3 id="_2-1-慢启动-slow-start" tabindex="-1">2.1 慢启动（Slow Start） <a class="header-anchor" href="#_2-1-慢启动-slow-start" aria-label="Permalink to &quot;2.1 慢启动（Slow Start）&quot;">​</a></h3><p>连接刚建立时，不知道网络当前的拥塞状况，不能一下子发大量数据，应该试探性地逐步提高发送速率。</p><p><strong>规则：</strong></p><ul><li>初始拥塞窗口 <code>cwnd = 1</code>（早期），现在一般是 <code>cwnd = 4~10</code> MSS（最大报文段长度）</li><li>每收到一个 ACK 确认，<code>cwnd += 1</code></li><li>每个 RTT（往返时间）后，<code>cwnd *= 2</code> → 指数增长</li></ul><p>指数增长很快就会达到一个阈值 <code>ssthresh</code>（slow start threshold）：</p><ul><li><code>cwnd &lt; ssthresh</code> → 保持慢启动（指数增长）</li><li><code>cwnd == ssthresh</code> → 进入拥塞避免（线性增长）</li></ul>',19)),(e(),o(d,null,{default:a(()=>[l(n,{id:"mermaid-198",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%E5%88%9D%E5%A7%8B%3A%20cwnd%3D1%5D%20--%3E%20B%5B%E6%AF%8F%E4%B8%AARTT%20cwnd%E5%8A%A0%E5%80%8D%5D%0A%20%20%20%20B%20--%3E%20C%7Bcwnd%20%3C%20ssthresh%3F%7D%0A%20%20%20%20C%20--%3E%7C%E6%98%AF%7C%20B%0A%20%20%20%20C%20--%3E%7C%E5%90%A6%7C%20D%5B%E8%BF%9B%E5%85%A5%E6%8B%A5%E5%A1%9E%E9%81%BF%E5%85%8D%5D%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=r(`<h3 id="_2-2-拥塞避免-congestion-avoidance" tabindex="-1">2.2 拥塞避免（Congestion Avoidance） <a class="header-anchor" href="#_2-2-拥塞避免-congestion-avoidance" aria-label="Permalink to &quot;2.2 拥塞避免（Congestion Avoidance）&quot;">​</a></h3><p>过了慢启动阈值后，不再指数增长，改为缓慢线性增长，避免过快导致拥塞。</p><p><strong>规则：</strong></p><ul><li>每收到一个 RTT 内的所有确认，<code>cwnd += 1</code></li><li>不管一个 RTT 内收到多少个 ACK，每个 RTT 只加 1</li><li>cwnd 呈线性增长：<code>cwnd = cwnd + 1/cwnd</code> ≈ 每个 RTT +1</li></ul><p>这样增长很慢，尽量延迟拥塞发生的时间，找到网络的最大容量。</p><h3 id="_2-3-拥塞发生后的处理" tabindex="-1">2.3 拥塞发生后的处理 <a class="header-anchor" href="#_2-3-拥塞发生后的处理" aria-label="Permalink to &quot;2.3 拥塞发生后的处理&quot;">​</a></h3><p>当发生拥塞时，通过什么现象判断？两种情况：</p><ol><li><strong>超时重传</strong>：说明网络拥塞很严重，丢包很多</li><li><strong>收到三个重复 ACK</strong>：说明只是个别丢包，网络还没到完全拥塞</li></ol><p>针对这两种情况，处理方式不同：</p><h4 id="情况一-超时触发拥塞" tabindex="-1">情况一：超时触发拥塞 <a class="header-anchor" href="#情况一-超时触发拥塞" aria-label="Permalink to &quot;情况一：超时触发拥塞&quot;">​</a></h4><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. ssthresh = cwnd / 2       // 阈值减半</span></span>
<span class="line"><span>2. cwnd = 1                  // 拥塞窗口重置为1</span></span>
<span class="line"><span>3. 重新进入慢启动阶段</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h4 id="情况二-三个重复-ack-触发-快重传" tabindex="-1">情况二：三个重复 ACK 触发（快重传） <a class="header-anchor" href="#情况二-三个重复-ack-触发-快重传" aria-label="Permalink to &quot;情况二：三个重复 ACK 触发（快重传）&quot;">​</a></h4><p><strong>快重传原理：</strong> 接收方收到一个失序报文段后，立刻发出对之前已正确接收报文段的重复确认，而不要等待自己发送数据时才捎带确认。发送方一连收到三个重复确认，就知道有报文段丢了，可以立即重传，不用等超时定时器过期。</p><p>快重传之后，进入<strong>快恢复</strong>，而不是慢启动。</p><p><strong>快恢复规则：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. ssthresh = cwnd / 2       // 阈值还是减半</span></span>
<span class="line"><span>2. cwnd = ssthresh           // 不是重置到1，直接设为阈值</span></span>
<span class="line"><span>3. 进入拥塞避免阶段（线性增长）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>为什么可以不回到慢启动？因为能收到三个重复 ACK，说明网络并没有完全堵死，只是轻微丢包，不需要从 1 开始慢慢涨。</p>`,17)),(e(),o(d,null,{default:a(()=>[l(n,{id:"mermaid-269",class:"mermaid",graph:"stateDiagram-v2%0A%20%20%20%20%5B*%5D%20--%3E%20%E6%85%A2%E5%90%AF%E5%8A%A8%3A%20cwnd%3D1%2C%20ssthresh%3D%E5%88%9D%E5%A7%8B%E5%80%BC%0A%20%20%20%20%E6%85%A2%E5%90%AF%E5%8A%A8%20--%3E%20%E6%8B%A5%E5%A1%9E%E9%81%BF%E5%85%8D%3A%20cwnd%20%3E%3D%20ssthresh%0A%20%20%20%20%E6%8B%A5%E5%A1%9E%E9%81%BF%E5%85%8D%20--%3E%20%E6%8B%A5%E5%A1%9E%E9%81%BF%E5%85%8D%3A%20cwnd%20%E7%BA%BF%E6%80%A7%E5%A2%9E%E9%95%BF%0A%20%20%20%20%E6%8B%A5%E5%A1%9E%E9%81%BF%E5%85%8D%20--%3E%20%E8%B6%85%E6%97%B6%3A%20%E5%8F%91%E7%94%9F%E8%B6%85%E6%97%B6%0A%20%20%20%20%E8%B6%85%E6%97%B6%20--%3E%20%E6%85%A2%E5%90%AF%E5%8A%A8%3A%20ssthresh%3Dcwnd%2F2%2C%20cwnd%3D1%0A%20%20%20%20%E6%8B%A5%E5%A1%9E%E9%81%BF%E5%85%8D%20--%3E%20%E5%BF%AB%E9%87%8D%E4%BC%A0%3A%203%E4%B8%AA%E9%87%8D%E5%A4%8DACK%0A%20%20%20%20%E5%BF%AB%E9%87%8D%E4%BC%A0%20--%3E%20%E5%BF%AB%E6%81%A2%E5%A4%8D%3A%20ssthresh%3Dcwnd%2F2%2C%20cwnd%3Dssthresh%0A%20%20%20%20%E5%BF%AB%E6%81%A2%E5%A4%8D%20--%3E%20%E6%8B%A5%E5%A1%9E%E9%81%BF%E5%85%8D%3A%20cwnd%20%3E%20ssthresh%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r('<div class="tip custom-block"><p class="custom-block-title">原始 Tahoe vs Reno</p><ul><li>TCP Tahoe（早期版本）：不管超时还是三个重复 ACK，都回到慢启动（cwnd=1）</li><li>TCP Reno（主流版本）：超时回慢启动，三个重复 ACK 走快恢复</li></ul></div><h3 id="_2-4-完整状态变化示例" tabindex="-1">2.4 完整状态变化示例 <a class="header-anchor" href="#_2-4-完整状态变化示例" aria-label="Permalink to &quot;2.4 完整状态变化示例&quot;">​</a></h3><p>假设初始：<code>cwnd = 1</code>, <code>ssthresh = 16</code></p><ol><li>慢启动：1 → 2 → 4 → 8 → 16（指数增长，到达阈值）</li><li>进入拥塞避免：16 → 17 → 18 → ... → 24（线性增长）</li><li>此时发生拥塞（收到三个重复 ACK）： <ul><li><code>ssthresh = 24 / 2 = 12</code></li><li><code>cwnd = 12</code></li><li>进入拥塞避免，继续线性增长</li></ul></li><li>如果这次是超时发生拥塞： <ul><li><code>ssthresh = 24 / 2 = 12</code></li><li><code>cwnd = 1</code></li><li>重新进入慢启动</li></ul></li></ol><hr><h2 id="三、经典拥塞控制算法演进" tabindex="-1">三、经典拥塞控制算法演进 <a class="header-anchor" href="#三、经典拥塞控制算法演进" aria-label="Permalink to &quot;三、经典拥塞控制算法演进&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>核心改进</th></tr></thead><tbody><tr><td>TCP Tahoe</td><td>慢启动 + 拥塞避免，都回到 cwnd=1</td></tr><tr><td>TCP Reno</td><td>加入快重传 + 快恢复，三个重复 ACK 不回 1</td></tr><tr><td>TCP NewReno</td><td>改进快恢复，处理多个丢包，partial ACK 处理</td></tr><tr><td>Cubic</td><td>二进制增长，延迟敏感长肥管道更友好，Linux 默认</td></tr><tr><td>BBR</td><td>基于模型的拥塞控制，不依赖丢包判断，Google 推出</td></tr></tbody></table><h3 id="cubic-算法简介" tabindex="-1">CUBIC 算法简介 <a class="header-anchor" href="#cubic-算法简介" aria-label="Permalink to &quot;CUBIC 算法简介&quot;">​</a></h3><p>Cubic 是 Linux 内核默认的拥塞控制算法，主要改进：</p><ul><li>不再是线性增长，而是<strong>三次函数增长</strong></li><li>增长曲线更平滑，在长肥管道（长带宽时延积网络）下更公平</li><li>RTT 不同的流之间公平性更好</li><li>能更快利用空闲带宽，也能在拥塞时更平稳减速</li></ul><hr><h2 id="四、bbr-拥塞控制" tabindex="-1">四、BBR 拥塞控制 <a class="header-anchor" href="#四、bbr-拥塞控制" aria-label="Permalink to &quot;四、BBR 拥塞控制&quot;">​</a></h2><p>BBR（Bottleneck Bandwidth and Round-trip propagation time）是 Google 在 2016 年提出的新型拥塞控制算法，现在已经广泛应用（YouTube、Google Cloud、Android 等）。</p><h3 id="_4-1-bbr-解决了什么问题" tabindex="-1">4.1 BBR 解决了什么问题？ <a class="header-anchor" href="#_4-1-bbr-解决了什么问题" aria-label="Permalink to &quot;4.1 BBR 解决了什么问题？&quot;">​</a></h3><p>传统拥塞控制（Reno、Cubic）都是通过<strong>丢包</strong>来判断拥塞：只要丢包就认为网络拥塞了，必须减速。</p><p>但现代互联网环境下：</p><ul><li>很多丢包不是因为拥塞，而是<strong>链路随机丢包</strong>（无线链路）</li><li>缓存都很大，不丢包不代表没有排队延迟</li><li>传统算法会因为偶尔丢包就大幅度减速，吞吐量上不去</li></ul><p>BBR 的核心思想：<strong>不通过丢包判断拥塞，而是直接测量瓶颈带宽和传播时延，基于模型控制发送速率</strong>。</p><h3 id="_4-2-bbr-核心模型" tabindex="-1">4.2 BBR 核心模型 <a class="header-anchor" href="#_4-2-bbr-核心模型" aria-label="Permalink to &quot;4.2 BBR 核心模型&quot;">​</a></h3><p>BBR 的核心是维护两个估计：</p><ol><li><strong>BtlBw</strong>：Bottleneck Bandwidth，最近 RTT 内测得的瓶颈带宽（最大能传多少）</li><li><strong>RTprop</strong>：Round-trip propagation time，最小传播时延（不排队情况下的 RTT）</li></ol><p>然后计算出<strong>带宽时延积 BDP</strong>：<code>BDP = BtlBw × RTprop</code></p><p>发送窗口：<code>cwnd = BDP × gain</code> → gain 是增益系数，用来控制填充程度</p><p>BDP 就是网络管道能容纳的飞行中（in-flight）数据量。BBR 目标就是让管道里正好放 BDP 这么多数据，不多也不少。</p><h3 id="_4-3-bbr-工作周期" tabindex="-1">4.3 BBR 工作周期 <a class="header-anchor" href="#_4-3-bbr-工作周期" aria-label="Permalink to &quot;4.3 BBR 工作周期&quot;">​</a></h3><p>BBR 运行分为两个阶段交替：</p><ol><li><strong>Startup 启动阶段</strong>：类似慢启动，指数速率探测带宽，直到速率停止增长，说明找到瓶颈了</li><li><strong>Drain 排空阶段</strong>：把发送速率降到 BDP，排空队列</li><li><strong>ProbeBW 探测带宽</strong>：在一个周期内，稍微加大一点速率探测是否有更多带宽可用，如果有就更新 BtlBw</li><li><strong>ProbeRTT 探测RTT</strong>：主动把 cwnd 降下来，测量最小 RTT，更新 RTprop</li></ol><p>和传统算法比：</p><ul><li>不依赖丢包，对随机丢包更鲁棒</li><li>在高带宽长时延链路（长肥网）下吞吐量更高</li><li>排队延迟更小，延迟更低</li><li>移动网络、无线网络下体验更好</li></ul><div class="warning custom-block"><p class="custom-block-title">BBR 存在的问题</p><p>BBR 在某些场景下（多个BBR流和多个Cubic流共享瓶颈），BBR 会抢占更多带宽，公平性不如 Cubic。BBRv2 改进了这个问题。</p></div><hr><h2 id="五、常见面试点深入" tabindex="-1">五、常见面试点深入 <a class="header-anchor" href="#五、常见面试点深入" aria-label="Permalink to &quot;五、常见面试点深入&quot;">​</a></h2><h3 id="慢启动一定会结束吗" tabindex="-1">慢启动一定会结束吗？ <a class="header-anchor" href="#慢启动一定会结束吗" aria-label="Permalink to &quot;慢启动一定会结束吗？&quot;">​</a></h3><p>不一定。如果初始 ssthresh 很大，网络一直不拥塞，cwnd 增长到接收窗口 rwnd 就不再增长了，一直停留在慢启动。</p><h3 id="为什么慢启动叫-慢-启动" tabindex="-1">为什么慢启动叫&quot;慢&quot;启动？ <a class="header-anchor" href="#为什么慢启动叫-慢-启动" aria-label="Permalink to &quot;为什么慢启动叫&quot;慢&quot;启动？&quot;">​</a></h3><p>相对于直接满速发送来说，它是慢的，从 1 开始试探性增长。但它本身是指数增长，其实增长很快。</p><h3 id="重复确认一定是丢包吗" tabindex="-1">重复确认一定是丢包吗？ <a class="header-anchor" href="#重复确认一定是丢包吗" aria-label="Permalink to &quot;重复确认一定是丢包吗？&quot;">​</a></h3><p>不一定，也可能是网络乱序到达，但三个重复确认可以作为丢包的一个很好启发式判断，所以快重传采用这个规则。</p><h3 id="快重传一定需要快恢复吗" tabindex="-1">快重传一定需要快恢复吗？ <a class="header-anchor" href="#快重传一定需要快恢复吗" aria-label="Permalink to &quot;快重传一定需要快恢复吗？&quot;">​</a></h3><p>在老的 Tahoe 版本，快重传之后还是回到慢启动。现在主流都是快重传+快恢复组合，因为三个重复 ACK 说明网络拥塞不严重，不需要从 1 开始。</p><hr><h2 id="六、交叉关联到其他模块" tabindex="-1">六、交叉关联到其他模块 <a class="header-anchor" href="#六、交叉关联到其他模块" aria-label="Permalink to &quot;六、交叉关联到其他模块&quot;">​</a></h2><ul><li><strong>滑动窗口流量控制</strong>：参见 <a href="./tcp">TCP 协议</a>，实际发送窗口是 <code>min(cwnd, rwnd)</code></li><li><strong>网络编程</strong>：TCP 拥塞控制由内核协议栈实现，应用层只需要通过 socket 读写，不需要自己处理</li><li><strong>Java NIO</strong>：参见 <a href="./../../java-advanced/io-nio/nio">Java 进阶：IO/NIO</a>，多路复用可以更好地处理大量连接，每个连接发送速率由内核拥塞控制自动调节</li></ul><hr><h2 id="七、经典高频面试题" tabindex="-1">七、经典高频面试题 <a class="header-anchor" href="#七、经典高频面试题" aria-label="Permalink to &quot;七、经典高频面试题&quot;">​</a></h2><h3 id="q1-说一下-tcp-拥塞控制的过程-慢启动、拥塞避免、快重传、快恢复分别是什么" tabindex="-1">Q1：说一下 TCP 拥塞控制的过程，慢启动、拥塞避免、快重传、快恢复分别是什么？ <a class="header-anchor" href="#q1-说一下-tcp-拥塞控制的过程-慢启动、拥塞避免、快重传、快恢复分别是什么" aria-label="Permalink to &quot;Q1：说一下 TCP 拥塞控制的过程，慢启动、拥塞避免、快重传、快恢复分别是什么？&quot;">​</a></h3><p><strong>参考答案：</strong> TCP 拥塞控制是为了防止发送过快导致网络拥塞丢包，核心四个算法：</p><ol><li><p><strong>慢启动</strong>：连接初始，cwnd 从 1（或几）MSS 开始，每收到一个 ACK cwnd+1，每个 RTT 后 cwnd 翻倍，指数增长。直到 cwnd 达到阈值 ssthresh，进入拥塞避免。目的是试探网络容量。</p></li><li><p><strong>拥塞避免</strong>：cwnd 超过阈值后，改为每个 RTT 只加 1 MSS，线性缓慢增长，尽量延缓拥塞发生。</p></li><li><p><strong>快重传</strong>：发送方收到三个重复 ACK，就判断发生了丢包，立刻重传丢失的报文段，不需要等超时定时器到期，减少重传超时时间。</p></li><li><p><strong>快恢复</strong>：当三个重复 ACK 触发重传时，ssthresh 减半，cwnd 直接设为 ssthresh，进入拥塞避免，而不回到慢启动。因为三个重复 ACK 说明只是轻微丢包，网络还有承载力，不需要从 1 开始。</p></li></ol><p>如果是超时触发，说明拥塞严重，ssthresh 减半，cwnd 重置为 1，回到慢启动。</p><h3 id="q2-慢启动一定慢吗-为什么叫这个名字" tabindex="-1">Q2：慢启动一定慢吗？为什么叫这个名字？ <a class="header-anchor" href="#q2-慢启动一定慢吗-为什么叫这个名字" aria-label="Permalink to &quot;Q2：慢启动一定慢吗？为什么叫这个名字？&quot;">​</a></h3><p><strong>参考答案：</strong> 慢启动叫&quot;慢&quot;是相对于直接全速发送来说的，它实际上是指数增长，速度非常快。它的意思是初始阶段试探性地慢慢提速，而不是一上来就全速发送把网络冲垮，所以叫慢启动。</p><p>比如初始 cwnd=1，10 个 RTT 后就是 2^10=1024，增长非常快。</p><h3 id="q3-流量控制和拥塞控制的区别是什么" tabindex="-1">Q3：流量控制和拥塞控制的区别是什么？ <a class="header-anchor" href="#q3-流量控制和拥塞控制的区别是什么" aria-label="Permalink to &quot;Q3：流量控制和拥塞控制的区别是什么？&quot;">​</a></h3><p><strong>参考答案：</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>流量控制</th><th>拥塞控制</th></tr></thead><tbody><tr><td>解决问题</td><td>发送方不要快过接收方处理能力</td><td>发送方不要快过网络承载能力</td></tr><tr><td>范围</td><td>端到端，点对点之间</td><td>全局，整个网络路径</td></tr><tr><td>控制参数</td><td>接收窗口 rwnd，由接收方通告</td><td>拥塞窗口 cwnd，由发送方根据网络状况计算</td></tr><tr><td>最终窗口</td><td>发送端取 min(cwnd, rwnd)</td><td></td></tr></tbody></table><p>简单说：流量控制管&quot;接收方能不能接住&quot;，拥塞控制管&quot;网络能不能扛得住&quot;。</p><h3 id="q4-bbr-和传统-cubic-reno-拥塞控制的核心区别是什么" tabindex="-1">Q4：BBR 和传统 Cubic/Reno 拥塞控制的核心区别是什么？ <a class="header-anchor" href="#q4-bbr-和传统-cubic-reno-拥塞控制的核心区别是什么" aria-label="Permalink to &quot;Q4：BBR 和传统 Cubic/Reno 拥塞控制的核心区别是什么？&quot;">​</a></h3><p><strong>参考答案：</strong></p><ul><li>传统算法（Reno、Cubic）都是<strong>基于丢包</strong>判断拥塞：只要发生丢包，就认为网络拥塞了，立刻把发送速率降下来。</li><li>BBR 是<strong>基于模型</strong>：不通过丢包判断，而是直接测量瓶颈带宽 B 和最小传播时延 RTT，计算出带宽时延积 BDP，维持管道中正好有 BDP 这么多数据，不排队也不空闲。</li></ul><p>优势：</p><ol><li>不依赖丢包，对无线链路的随机丢包更鲁棒</li><li>排队延迟更低，端到端延迟更小</li><li>高带宽长时延链路（长肥网）下吞吐量更高</li></ol><p>劣势：</p><ol><li>多个流共享瓶颈时，BBR 公平性不如 Cubic（BBRv2 改进了）</li><li>小缓存网络可能会有一定丢包率偏高</li></ol><h3 id="q5-为什么需要快恢复-快恢复解决了什么问题" tabindex="-1">Q5：为什么需要快恢复？快恢复解决了什么问题？ <a class="header-anchor" href="#q5-为什么需要快恢复-快恢复解决了什么问题" aria-label="Permalink to &quot;Q5：为什么需要快恢复？快恢复解决了什么问题？&quot;">​</a></h3><p><strong>参考答案：</strong> 在没有快恢复的 TCP Tahoe 中，不管是超时还是三个重复 ACK，发生拥塞后都把 cwnd 重置为 1，进入慢启动。</p><p>但三个重复 ACK 说明什么？说明网络只是丢了一个包，其他包都能正常到达，网络并没有严重拥塞。如果这时候也把 cwnd 降到 1，会导致吞吐量急剧下降，浪费带宽。</p><p>快恢复就是：收到三个重复 ACK 后，只把 ssthresh 减半，cwnd 直接设为 ssthresh，然后进入拥塞避免，避免了不必要的慢启动，吞吐量损失更小，性能更好。</p><h3 id="q6-慢启动阈值-ssthresh-是怎么变化的" tabindex="-1">Q6：慢启动阈值 ssthresh 是怎么变化的？ <a class="header-anchor" href="#q6-慢启动阈值-ssthresh-是怎么变化的" aria-label="Permalink to &quot;Q6：慢启动阈值 ssthresh 是怎么变化的？&quot;">​</a></h3><p><strong>参考答案：</strong></p><ul><li>初始值一般是 16 MSS（不同实现可能不同）</li><li>每次发生拥塞（无论是超时还是三个重复 ACK），ssthresh 都会被设置为当前 cwnd 的一半</li><li>慢启动阶段 cwnd 一直增长，直到到达 ssthresh 就进入拥塞避免</li><li>所以随着不断发生拥塞，ssthresh 会不断变小，逐渐逼近网络真实容量</li></ul>',70))])}const C=i(p,[["render",u]]);export{q as __pageData,C as default};
